import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import {
  LayoutDashboard,
  Activity,
  FileText,
  Server,
  Settings,
  LogOut
} from 'lucide-react';
import clsx from 'clsx';
import TTLogo from './TTLogo';

const Sidebar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const NavItem = ({ to, icon: Icon, label, badge, roles }: any) => {
    if (roles && user && !roles.includes(user.role)) return null;
    return (
      <NavLink
        to={to}
        className={({ isActive }) =>
          clsx(
            'flex items-center rounded-lg px-4 py-3 text-sm font-semibold transition-all mb-1',
            isActive
              ? 'bg-[#edf2fe] text-[#2563eb] shadow-[inset_4px_0_0_0_#2563eb]'
              : 'text-[#626e82] hover:bg-gray-50'
          )
        }
      >
        <Icon className="mr-3 h-5 w-5" />
        {label}
        {badge && (
          <span className="ml-auto flex h-5 items-center justify-center rounded-full bg-red-100 px-2 text-[10px] font-bold text-red-600">
            {badge}
          </span>
        )}
      </NavLink>
    );
  };

  return (
    <div className="flex h-full w-[260px] flex-col bg-white border-r border-gray-200">
      <div className="flex h-[100px] flex-col items-center justify-center pt-4">
        <TTLogo />
        <div className="mt-3 text-center">
          <h2 className="font-bold text-[#1f2937] tracking-tight">TT SecureWatch</h2>
          <p className="text-[11px] font-semibold tracking-wide">
            <span className="text-[#3b82f6]">Tunisie Telecom</span> <span className="text-[#9ca3af]">SOC</span>
          </p>
        </div>
      </div>

      <div className="flex-1 overflow-auto px-4 mt-6">
        <div className="mb-6">
          <h3 className="px-4 text-xs font-bold uppercase tracking-wider text-gray-400 mb-2">Principal</h3>
          <nav>
            <NavItem to="/dashboard" icon={LayoutDashboard} label="Tableau de bord" />
            <NavItem to="/alerts" icon={Activity} label="Alertes & Menaces" badge="99+" />
          </nav>
        </div>

        <div className="mb-6">
          <h3 className="px-4 text-xs font-bold uppercase tracking-wider text-gray-400 mb-2">Analytique</h3>
          <nav>
            <NavItem to="/reports" icon={FileText} label="Rapports" />
            <NavItem to="/assets" icon={Server} label="Actifs" roles={['ADMIN']} />
          </nav>
        </div>

        <div className="mb-6">
          <h3 className="px-4 text-xs font-bold uppercase tracking-wider text-gray-400 mb-2">Système</h3>
          <nav>
            <NavItem to="/settings" icon={Settings} label="Configuration" />
          </nav>
        </div>
      </div>

      <div className="p-4 border-t">
        <button
          onClick={handleLogout}
          className="flex w-full items-center rounded-lg px-4 py-3 text-sm font-semibold text-red-500 hover:bg-red-50 transition-colors"
        >
          <LogOut className="mr-3 h-5 w-5" />
          Déconnexion
        </button>
      </div>
    </div>
  );
};

export default Sidebar;
